Implementasi Observer Pattern yang robust, type-safe, dan thread-safe untuk lingkungan produksi. Kode ini menggunakan `abc` untuk enforce interface dan `threading` untuk konkurensi aman.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import threading
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Observer(ABC):
    """Interface untuk Observer."""

    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject(ABC):
    """Interface untuk Subject."""

    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class ConcreteSubject(Subject):
    """Implementasi Subject yang thread-safe."""

    def __init__(self) -> None:
        self._state: Any = None
        self._observers: List[Observer] = []
        self._lock = threading.Lock()

    def attach(self, observer: Observer) -> None:
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)
                logger.info("Observer attached successfully.")

    def detach(self, observer: Observer) -> None:
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)
                logger.info("Observer detached successfully.")

    def notify(self) -> None:
        """Notify semua observer dengan lock untuk mencegah race condition."""
        with self._lock:
            observers_snapshot = list(self._observers)

        for observer in observers_snapshot:
            try:
                observer.update(self)
            except Exception as e:
                logger.error(f"Error notifying observer: {e}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

class ConcreteObserver(Observer):
    """Implementasi Observer konkret."""

    def __init__(self, name: str) -> None:
        self._name = name

    def update(self, subject: Subject) -> None:
        if isinstance(subject, ConcreteSubject):
            logger.info(f"[{self._name}] Received update. New State: {subject.get_state()}")

# --- Contoh Penggunaan ---
if __name__ == "__main__":
    subject = ConcreteSubject()

    obs1 = ConcreteObserver("Observer-1")
    obs2 = ConcreteObserver("Observer-2")

    subject.attach(obs1)
    subject.attach(obs2)

    # Trigger update
    subject.set_state({"status": "secure", "code": 200})

    # Cleanup
    subject.detach(obs1)
    subject.set_state({"status": "updated", "code": 201})
```

### Catatan Teknis:
1.  **Thread Safety**: Menggunakan `threading.Lock` pada `attach`, `detach`, dan `notify`. Krusial untuk mencegah race condition jika observer dimodifikasi saat iterasi berlangsung.
2.  **Snapshotting**: Saat `notify`, kita menyalin list observer (`observers_snapshot`) di dalam lock, lalu melepas lock sebelum memanggil callback observer. Ini mencegah deadlock jika observer mencoba mengubah subject saat dipanggil.
3.  **Error Handling**: `try-except` pada loop notify memastikan satu observer yang error tidak menghentikan notifikasi ke observer lain.
4.  **Type Hinting**: Menggunakan `typing` untuk maintainability dan deteksi dini kesalahan tipe data.

Gunakan pola ini untuk sistem event logging, monitoring server, atau update status real-time tanpa coupling yang ketat.
